    -- Geri Kazanılmış Hazineler
    ["1360"] = {
    ["Title"]="Geri Kazanılmış Hazineler",
    ["Description"]="Çorak Topraklar'daki Uldaman kazı alanında kazıcı olarak iyi bir işim vardı... ta ki o lanet troglar ortaya çıkana kadar. Postuma zar zor zarar vererek kaçtım, başka da bir şeyim yoktu. Kaosun içinde en değerli eşyamı bıraktım. Göğsümde troglardan güvende, elbette, ama tam da onların ortasında.NEW_LINENEW_LINEOnu benim için getirebilirseniz, size hem onur hem de para olarak borçlu olurum! Kuzey Ortak Salon'un sonunda üzerinde adımın yazılı olduğu bir sandık var. İçeri girmek için ihtiyacın olan o.",
    ["Objectives"]="Krom Stoutarm'ın değerli eşyasını Uldaman'ın Kuzey Ortak Salonu'ndaki sandığından al ve Ironforge'da ona getir.",
    ["Progress"]="Peki şimdi, sandığıma girip hazinemi almak için o trogları yeterince uzun süre tokatlayabilecek misin?",
    ["Completion"]="Ah, kendimi yeniden tamamlanmış hissediyorum - teşekkür ederim.NEW_LINENEW_LINEBazı cüceler metalin parlaklığına, bazıları da mücevherlerin ışıltısına değer verebilir... ama elinde değerli bir stein olmayan bir Stoutarm, Stoutarm bile sayılmaz!",
    ["minlevel"]="0",
    ["questlevel"]="0",
    }, -- end Geri Kazanılmış Hazineler

