    -- Doğruluk Sınavı
    ["1653"] = {
    ["Title"]="Doğruluk Sınavı",
    ["Description"]="Aslında Jordan'ın kendisinin de size teşekkür etmek isteyeceğinden hiç şüphem yok ve karısının güvende olduğunu bildirmek için bir haberciye ihtiyacım olduğuna göre, bence mükemmel bir seçim olursunuz.NEW_LINENEW_LINEJordan, babasının zanaatına olan bağlılığı onu başka bir yola götürmeden önce bir Işık şovalyesi olacaktı - yaşam tarzımızı yakından tanıyor ve en sadıklarımız arasında sayılıyor.NEW_LINENEW_LINEHâlâ Ironforge'da olmalı--gün içinde kapıların dışında çalışmayı seviyor, serin dağ havasıyla ilgili bir şey.",
    ["Objectives"]="Ironforge'da Jordan Stilwell ile konuşun",
    ["Progress"]="",
    ["Completion"]="İyi günler, YOUR_NAME. Işık seninle, eminim?NEW_LINENEW_LINEBu da ne? Seni Duthorian mı gönderdi? Karım, o nasıl? Gidersem sorun çıkacağını biliyordum. Lütfen bana onun... oh, şükürler olsun. Güvende olduğuna çok sevindim. Defias bu saldırılardan çok önce de bir tehditti ama şimdi Kral'ın danışmanları bunu inkar edemiyor.NEW_LINENEW_LINEDuthorian başka ne söyleyecekti?NEW_LINENEW_LINEKarımı korumak için gönderilen kişi sen misin? O zaman sana tekrar teşekkür ederim, YOUR_NAME. Bundan daha iyi bir cesaret testi düşünemezdim.",
    ["minlevel"]="0",
    ["questlevel"]="0",
    }, -- end Doğruluk Sınavı

    -- Doğruluk Sınavı
    ["1654"] = {
    ["Title"]="Doğruluk Sınavı",
    ["Description"]="Eğer böyle bir şeyi kabul edersen seni ödüllendirmek isterim. Beni yanlış anlamayın, cömertliğim sizin ne kadar yardımcı olabileceğinize bağlı, ancak böyle bir ittifaktan ikimizin de büyük fayda sağlayacağını düşünüyorum.NEW_LINENEW_LINESenin için başardıklarına layık, şovalyeliğin ve Işığın sembolü bir silah yapacağım, ancak bunu yapmak için ihtiyacım olan eşyaları toplamalısın. Eşyalar hakkında notlar almaya başladım bile, sadece onları toplayacak kadar cesur ve yetenekli birine ihtiyacım var. Ne diyorsun, {клас} ?",
    ["Objectives"]="Jordan'ın Silah Notlarını kullanarak Beyaz Taş Meşe Kerestesi, Bailor'ın Rafine Cevher Sevkiyatı, Jordan'ın Demirci Çekici ve bir Kor Mücevheri bulun ve Ironforge'daki Jordan Stilwell'e geri götürün.",
    ["Progress"]="Aradığınız eşyaları elde etmek zor olacak, ancak sizi temin ederim ki, sizin için yapacağım silah bu çabaya değecek.NEW_LINENEW_LINEBugüne kadarki en iyi çalışmam olacak ve bana yaptığınız hizmet için sadece küçük bir ödeme olacak.",
    ["Completion"]="Bu harika! Tüm eşyaları aldınız.NEW_LINENEW_LINEBunlarla sana büyük bir silah yapmak benim için sorun olmaz. Aslında bunu yapmak için bir süredir planlarım vardı. Sadece malları toplamaya fırsatım olmadı. Teşekkür ederim, YOUR_NAME.NEW_LINENEW_LINEBabamın çekicine tekrar sahip olmak güzel bir duygu... ve bir Kor mücevheri. Bunlardan birini göreceğimi hiç düşünmemiştim.",
    ["minlevel"]="0",
    ["questlevel"]="0",
    }, -- end Doğruluk Sınavı

    -- Bailor'ın Cevher Sevkiyatı
    ["1655"] = {
    ["Title"]="Bailor'ın Cevher Sevkiyatı",
    ["Description"]="Ah, beni korkuttun, $G(adamım;kadın)! Düşüncelere daldığımı göremiyor musun?NEW_LINENEW_LINEBu da ne? Jordan'ın sevkiyatı... Ironforge'a. Ahhh, evet, neden bahsettiğini biliyorum. Mo'grosh devleri... Eski dostumun cevher sevkiyatını onlar aldı. Kervan Sulak Topraklar'dan buraya geliyordu ve pusuya düşürüldü. Saldırıdan kurtulan muhafız birkaç gün önce öldü - şifacı onlara yeterince hızlı ulaşamadı.NEW_LINENEW_LINESevkiyatı istiyorsanız, Loch'un kuzeydoğusuna gitmeniz gerekecek. Orada bir yerde olmalı.",
    ["Objectives"]="Jordan'ın Cevher Sevkiyatını Loch Modan'daki Bailor Stonehand'e getir.",
    ["Progress"]="Ee, şansın yaver gitti mi? Haha, o devler henüz seni alt edemedi, değil mi?",
    ["Completion"]="Evet, evet, işte bu. Ha! Gerçekten oraya gidip o devlerle savaşacağını bilseydim, sana sadece bu şey yerine alacağın şeylerin bir listesini verirdim. Ama burada benim için iş yapmıyorsun, değil mi?NEW_LINENEW_LINEAnlaşma anlaşmadır; Jordan benim alaşımımdan bir sevkiyat istedi, alacağı şey de bu.NEW_LINENEW_LINEOnlara benden selam söyle ve güvende ol, {клас}.",
    ["minlevel"]="0",
    ["questlevel"]="0",
    }, -- end Bailor'ın Cevher Sevkiyatı

    -- Tamamlanmamış Bir Görev
    ["1656"] = {
    ["Title"]="Tamamlanmamış Bir Görev",
    ["Description"]="YOUR_NAME Lütfen, size yalvarıyorum, bana yardım edebilir misiniz? Mesa'daki görevlerimi henüz tamamlamadım -Güç Ayini'nin ortasındayım- ve babam bu kürkleri Bloodhoof'taki hana götürmemi istedi.NEW_LINEHem ayinimi hem de babam için bu görevi tamamlayacak kadar dinlenmiş değilim. Benim için devam edebilir misin?NEW_LINENEW_LINEHan hoş ve uzun seyahatleriniz sırasında dinlenmek için mükemmel bir yer. Gördüğünüzde eminim siz de aynı fikirde olacaksınız.",
    ["Objectives"]="Kürk Demetini Bloodhoof Köyü'ndeki Hancı Kauth'a getirin.",
    ["Progress"]="Evet, genç olan? Kauth senin için ne yapabilir?NEW_LINENEW_LINEMesa'dan buraya yolculuk kimileri için büyük bir yük, kimileri içinse hoş bir manzara olabilir. Sizin için hangisi acaba?",
    ["Completion"]="Ah, beklediğim kürkler. Teşekkür ederim.NEW_LINENEW_LINEBunlar beklediğimden daha hızlı geldi. Burada kalmak isteyen herkes için iyi battaniyeler olacaklar.NEW_LINENEW_LINELütfen istediğiniz kadar kalmakta özgürsünüz. Han'ım her zaman açıktır ve tüm halkımız burada hoş karşılanır. Ve iyi bir gece dinlenmesini hafife almayın, seyahat ederken büyük bir fark yaratabilir.",
    ["minlevel"]="0",
