    -- Strahad'ı Aramak
    ["3001"] = {
    ["Title"]="Strahad'ı Aramak",
    ["Description"]="Geçmişte size beceriler öğrettim ama artık başka birinin size öğretme zamanı geldi. O Ratchet'te ve adı Strahad. O bir insan, ama bu sizi onun zayıf olduğunu düşünmeye itmesin, ne de düşmanınız... en azından şimdilik. O güçlüdür ve saygı duyulmalıdır. Sana daha büyük çağrıları öğretebilir, hazırlıklı olduğunu düşündüğüm çağrıları. Şimdi ona git.NEW_LINENEW_LINEOnu Ratchet'te bulabilirsin... liman kentinin yukarısında, oradaki kulenin yanında.",
