    -- Kazınmış Parşömen
    ["3087"] = {
    ["Title"]="Kazınmış Parşömen",
    ["Description"]="Ah, sen yokken sana bir parşömen geldi, YOUR_NAME.NEW_LINENEW_LINEZamanın olduğunda oku. Eğer yanılmıyorsam, avcı eğitmeni Karranisha'dan geldi. Hazır olduğunda seninle konuşacakları var.",
