    }, -- end Kazınmış Parşömen

    -- Şifreli Parşömen
    ["3088"] = {
    ["Title"]="Şifreli Parşömen",
    ["Description"]="Ah, sen yokken sana bir parşömen geldi, YOUR_NAME.NEW_LINENEW_LINEZamanın olduğunda oku. Yanılmıyorsam, haydut eğitmen Rwag'dan geldi. Hazır olduğunda seninle konuşacakları var.",
    ["Objectives"]="Şifreli Parşömeni okuyun ve Denemeler Vadisi'nde Rwag ile konuşun.",
    ["Progress"]="Shhh, çok yüksek sesle değil. Oradaki Nartok'a güvenmiyorum. Mağaranın derinliklerinde benden daha fazla saklanmak zorunda olan biri hafife alınmamalı.NEW_LINENEW_LINEUmarım yolunu bulmakta sorun yaşamamışsındır?",
    ["Completion"]="Artık nerede durduğumu bildiğine göre, sana haber vermeliyim: Parçalanmış El benden sana göz kulak olmamı istedi. Seni eğitmemi ve ihtiyaç duyabilecekleri her şeyden haberdar etmemi istiyorlar. Henüz onlara yardım etmekle ilgilenmiyor olsan bile - ki ilgilenmemen aptallık olur - seni eğitmek için elimden geleni yapacağım... küçük bir ücret karşılığında. Hazır olduğunu düşündüğün zaman bana geri gel ve ne öğrenmeye hazır olduğunu görelim.",
    ["minlevel"]="0",
