    }, -- end Şifreli Parşömen

    -- Rün Yazıtlı Parşömen
    ["3089"] = {
    ["Title"]="Rün Yazıtlı Parşömen",
    ["Description"]="Ah, sen yokken sana bir parşömen geldi, YOUR_NAME.NEW_LINENEW_LINEZamanın olduğunda oku. Yanılmıyorsam, şaman eğitmeni Shikrik'ten geldi. Hazır olduğunda seninle konuşacakları var.",
