    -- Lekeli Parşömen
    ["3090"] = {
    ["Title"]="Lekeli Parşömen",
    ["Description"]="Ah, sen yokken sana bir parşömen geldi, YOUR_NAME.NEW_LINENEW_LINEElimden geldiğince büyücülerle uğraşmaktan kaçınırım ama vaktin olduğunda okuman gerektiğini düşünüyorum. Yanılmıyorsam, yeni atanan eğitmeniniz Nartok'tan geldi. Hazır olduğunuzda sizinle konuşacakları var.",
    ["Objectives"]="Lekeli Parşömeni okuyun ve Denemeler Vadisi'nde Nartok ile konuşun.",
    ["Progress"]="Sonunda geldiniz... hem de gizlice. Güzel.NEW_LINENEW_LINEDünyamız aptallarla dolu, Asatokta. Kudretli Thrall'ın bile çoğu kişinin görebileceğinden daha büyük kusurları var. Bu toprakları tamamen bizim yapmak için gereken güce sırtını dönüyor! Bizler Cehennem'den gelen yaratıklar tarafından manipüle edilen ve kullanılan insanlar değiliz. Biz kendi halkımızız. Gururluyuz... ve güçlüyüz.",
    ["Completion"]="Ve şimdi sen de bizim saflarımıza katıldın. Yanlış anlama, Asatokta. Pek çok kişinin kıskanacağı bir güce erişmiş olman, kolayca kabul edileceğin anlamına gelmez. Thrall türümüzün Orgrimmar'a girmesine izin veriyor çünkü biz hâlâ onun soydaşlarıyız; bize sırtını dönemez, yoksa onu köleleştiren insanlar kadar zavallı oluruz. Demek istediğim şu: dikkatli olun. Güçlü olabilirsiniz, ama aptalsanız, o zaman ölmüş sayılırsınız.NEW_LINENEW_LINEBüyü eğitimine ihtiyacın varsa bana dön.",
    ["minlevel"]="0",
    ["questlevel"]="0",
    }, -- end Lekeli Parşömen

    -- Basit Not
    ["3091"] = {
    ["Title"]="Basit Not",
    ["Description"]="Az önce bir haberci seni arıyordu, YOUR_NAME. Sanırım savaşçı eğitmeni Harutt tarafından gönderildi. Eğer bu not Harutt'tan geldiyse, içeriğini okumakta gecikmezdim.",
    ["Objectives"]="Basit Not'u okuyun ve Narache Kampı'ndaki Harutt Thunderhorn ile konuşun.",
    ["Progress"]="Ah, sonunda geldin, {клас}. Notumda yalan söylemedim, YOUR_NAME. Biz de özel bir türüz, kabilemizin druidleri ya da şamanlarından farklı değiliz. Siz de aynı derecede önemlisiniz. Sınırlarımızı savunmak, sentorları avlamak ve savaşa gitmek için çağrılanlar bizleriz.",
    ["Completion"]="Her birimiz kabilemizde bir rol oynuyoruz. Her birimiz aynı törenlerden geçmeliyiz. Gururunuzun size aksini söylemesine asla izin vermeyin.NEW_LINENEW_LINESavaşın görkemini arayan ve en eski atalarımızın yollarını izleyen yeni savaşçıları eğitmek için burada kalıyorum. Kendini hazır hissettiğinde bana geri dön, seni daha fazla eğitmek için elimden geleni yapacağım. Kabilenin onayıyla git, YOUR_NAME.",
    ["minlevel"]="0",
