    -- Kazınmış Not
    ["3092"] = {
    ["Title"]="Kazınmış Not",
    ["Description"]="Az önce bir haberci seni arıyordu, YOUR_NAME. Sanırım avcı eğitmeni Lanka tarafından gönderildi. Eğer bu not Lanka'dan geldiyse, içeriğini okumam uzun sürmez.",
    ["Objectives"]="Kazınmış Notu okuyun ve Narache Kampındaki Lanka Farshot ile konuşun.",
    ["Progress"]="Narache Kampı'na hoş geldin Clisha. Senin hakkında iyi şeyler duydum. Soyun güçlü ve yaşlıların çoğu şimdiden yetenekli olduğunu düşünüyor. Ama bunu test edeceğiz.NEW_LINENEW_LINEMulgore ovaları bir süre senin evin olacak, burayı çok iyi öğrenmek için elinden geleni yapmalısın. Bir gün daha büyük becerilerde ustalaşmak için bilmediğin topraklara seyahat edeceksin. Buna hazır olmalısın.",
    ["Completion"]="Benim görevim de size mesleğimizin temellerini öğreterek hazırlıklı olmanızı sağlamaktır - evcil hayvanınızı nasıl evcilleştireceğinizi, tüfeğinizi nasıl ateşleyeceğinizi ve gerekli olacak diğer birçok beceriyi.NEW_LINENEW_LINEAvcılar geleneğimizin ve tarihimizin güçlü bir parçasıdır, Clisha. Kabile için ne kadar önemli olduğunu hatırlasan iyi edersin. Halkımıza iyi hizmet edersen saygı ve hürmet görürsün.",
    ["minlevel"]="0",
    ["questlevel"]="0",
    }, -- end Kazınmış Not

    -- Rune Yazılı Not
    ["3093"] = {
    ["Title"]="Rune Yazılı Not",
    ["Description"]="Az önce bir haberci seni arıyordu, YOUR_NAME. Sanırım şaman eğitmeni Meela tarafından gönderildi. Eğer bu not Meela'dan geldiyse, içeriğini okumakta gecikmezdim.",
    ["Objectives"]="Rün Yazıtlı Notu okuyun ve Narache Kampında Meela Dawnstrider ile konuşun.",
    ["Progress"]="Gökten su yağar gibi, işte karşımdasınız. Aceleniz beni memnun etti. Bu, hem toplantımızın hem de burada bulunmanın önemini anladığın anlamına geliyor. Ben bir lider değilim ama elementlerden anlarım ve halkımızın ruhlarıyla konuşabilirim. Size de aynısını yapmayı öğreteceğim.",
    ["Completion"]="Önümüzdeki günlerde birçok kez buluşacağız. Her seferinde umarım yanımdan biraz daha güçlü... biraz daha hazırlıklı ayrılacaksınız. Ebedi Alev gibi, ruhunuz da parlak ve sıcak yanacak.NEW_LINENEW_LINEŞimdi git, YOUR_NAME. Git ve kendini test et. İhtiyacın olduğunda senin için burada olacağım.",
    ["minlevel"]="0",
    ["questlevel"]="0",
    }, -- end Rune Yazılı Not

    -- Verdant Note
    ["3094"] = {
    ["Title"]="Verdant Note",
    ["Description"]="Az önce bir haberci seni arıyordu, YOUR_NAME. Sanırım onu Druid eğitmeni Gart gönderdi. Eğer bu not Gart'tan geldiyse, içeriğini okumakta gecikmezdim.",
    ["Objectives"]="Verdant Note'u okuyun ve Narache Kampı'nda Gart Mistrunner ile konuşun.",
    ["Progress"]="Geldiniz. Bu iyi bir şey. Atalarımızın ruhları Mulgore ve ötesinde huzursuz oldular, ama nedenini söyleyemem. Doğanın ruhlarını dinlemeyi öğrenmek ve onların avatarı olarak hareket etmek sonsuza dek senin görevin olacak. Buna dikkat edin.",
    ["Completion"]="Ortak bir bağı paylaşıyor olsak da, gece elflerinden pek hoş bir karşılama beklemeyin. Gururları hâlâ görüşlerini kısıtlıyor ama bu bizi ilgilendirmez. Tek ilgilenmeniz gereken Toprak Ana'nın öğretileri ve bilgeliğiniz arttıkça ben de size bildiklerimi öğreteceğim.NEW_LINENEW_LINEBana sık sık dön, YOUR_NAME. Toprak Ana'nın kendini en çok adayanlara inanılmaz yetenekler bahşettiğini göreceksin.",
    ["minlevel"]="0",
