    -- Cliffspring Nehri
    ["4762"] = {
    ["Title"]="Cliffspring Nehri",
    ["Description"]="Cliffspring Nehri kötüleşmeye ve bozulmaya başladı. Mist's Edge'e dökülüyor ve korkarım bu yıkama yakında Auberdine'i de etkileyecek. Nehrin yukarısındaki Blackwood furbolglarının bu kirliliğe neden olduğundan şüpheleniyorum, ama aynı zamanda bunun gerçek kökeninin onlar olmadığından da şüpheleniyorum.NEW_LINENEW_LINEBu örnekleme tüpünü alın ve kuzeyimizdeki nehrin ağzına gidin. İlk şelaleye doğru ilerleyin ve oradaki havuzdan bir numune alın. Tepenizde bir köprü göreceksiniz. Numune aldıktan sonra Auberdine'de bana dönün.",
    ["Objectives"]="Auberdine'in kuzeyinde Cliffspring Nehri boyunca uzanan ilk şelaleye gidin ve oradaki havuzdan bir örnek alın.NEW_LINENEW_LINECliffspring Nehri Örneği ile Auberdine'deki Thundris Windweaver'a dönün.",
    ["Progress"]="Cliffspring Nehri'nin kirlenmesi Darkshore'da endişe verici bir eğilimin başlangıcı. Sağladığınız örnek bir plan oluşturmamıza yardımcı olacak... bir saldırı planı, şüphelenmeye başlıyorum.",
    ["Completion"]="Bu suyun ne kadar kirli olduğu sürpriz değil, ama ne kadar kokuştuğuna bir bakın! Görünüşe göre bir an önce harekete geçilmesi gerekiyor, ha YOUR_NAME ?NEW_LINENEW_LINEDoğumuzda Felwood var; geçmişte de gördüğüm üzere bu yozlaşmanın asıl kaynağı orası. Bu numunenin bunu doğrulayacağını tahmin ediyorum. Burada bunun için bir tedavi uygulayabiliriz, ancak denemek için bile yardıma ihtiyacımız olacak. O zaman geldiğinde YOUR_NAME Umarım ihtiyacımız olan yardımı sağlayabilirsiniz.",
    ["minlevel"]="0",
    ["questlevel"]="0",
    }, -- end Cliffspring Nehri

    -- Blackwood Bozuldu
    ["4763"] = {
    ["Title"]="Blackwood Bozuldu",
    ["Description"]="Furbolg yozlaşmasının bir kaynağının da satirler olduğunu öğrendik. Büyüyü yönlendirdikleri tılsımlar aracılığıyla hakimiyetlerini sürdürüyorlar. Eğer furbolgların kurtuluş şansı varsa, satir bozguncusunu tuzağa düşürmeli ve o tılsımı almalıyız!NEW_LINENEW_LINEBu kaseyi ay evimizde doldurun ve kuzey kamplarından furbolgların yiyeceklerinden örnekler alın. Onları karıştır ve nehrin yanındaki şenlik ateşinin yanına koy; yiyen tüm furbolglar satir bozguncuyu cezbedecek kadar temizlenecek... o zaman onu öldürmelisin!",
    ["Objectives"]="Auberdine Moonwell'deki Boş Temizleme Kasesini Doldurun.NEW_LINENEW_LINEKuzey Blackwood furbolg kamplarından bir meyve, fındık ve tahıl örneği toplayın.NEW_LINENEW_LINEKaseyi karıştırın ve kuzey kampındaki Cliffspring Nehri'ne en yakın şenlik ateşinin yanına koyun, böylece satir bozucuyu çağırın.NEW_LINENEW_LINEYozlaşma Tılsımını al ve Auberdine'deki Thundris Windweaver'a getir.",
    ["Progress"]="Yozlaşma Tılsımı sadece doğanın dengesini bozmaya yarayan uğursuz bir alettir. Bu eşyayı furbolglara eziyet eden satirden alıp imha etmem için bana getirdiğinizde, bugün büyük bir zafer kazanmış olacağız!",
    ["Completion"]="Ormanımızı yozlaşma güçlerinden geri almak için bu savaşa daha yeni başladık, ancak bugün bir savaş kazanıldı! YOUR_NAME Auberdine halkı size asla kolay kolay ödenemeyecek bir minnet borçludur. Lütfen bunu teşekkürlerimizle birlikte kabul edin. Bugün burada öğrendiklerimiz, bir gün tüylü dostlarımızı işkencenin zincirlerinden ebediyen kurtarabilir.",
    ["minlevel"]="0",
    ["questlevel"]="0",
    }, -- end Blackwood Bozuldu

    -- Rüzgar Sürücüsü
    ["4767"] = {
    ["Title"]="Rüzgar Sürücüsü",
    ["Description"]="Usta rüzgar binicileri için daha fazla wyvern toplamakla görevlendirildim. Sayıları giderek artıyor ve ben de bir gün rüzgâr binicisi olmayı umuyorum. Ancak, talebi karşılayacak kadar wyvern yetiştiremiyoruz. Belki sen bana yardım edebilirsin, YOUR_NAME.NEW_LINENEW_LINEBiraz wyvern yumurtası toplamak için Highperch'e gitmeni istiyorum. Buradan, kanyon duvarları boyunca kuzeybatıya doğru ilerle ve seni Highperch'e götürecek bir rampaya ulaş. Dikkatli ol, wyvernler yumurtalarına karşı çok korumacıdırlar ve davetsiz misafirlere karşı nazik olmayacaklardır.",
    ["Objectives"]="Freewind Post'taki Elu'ya 10 Highperch Wyvern Yumurtası getir.",
