    -- Çağrıya Kulak Vermek
    ["5923"] = {
    ["Title"]="Çağrıya Kulak Vermek",
    ["Description"]="Affedersin, dostum.NEW_LINENEW_LINEMathrengyl Bearwalker'ın seninle konuşmak istediğini bildirdiğini öğrendim. Görünüşe göre bir druid olarak eğitimin yeni bir hayata başlamak üzere ve seni bizzat kendisi eğitecek. Mathrengyl, Baş Druid'in doğrudan asistanıdır ve Teldrassil'de bulabileceğiniz en bilge ve bilge druidlerden biridir.NEW_LINENEW_LINEDarnassus'un Cenarion yerleşim bölgesinde, Fandral Staghelm'in ağacının ikinci katında bulunur.",
