    ["minlevel"]="0",
    ["questlevel"]="0",
    }, -- end Mor'zul Kan Getiren

    -- Kanın Öfkesi
    ["7563"] = {
    ["Title"]="Kanın Öfkesi",
    ["Description"]="Dreadsteed'ler başka bir dünyada, Xoroth'un ateşli düzlüklerinde yaşar ve o meşhur canavarlardan birini bağlamak için güçlü glifler çağırmalısın. Glifleri senin için bir parşömene yazabilirim ama önce özel bir mürekkebe ihtiyacım olacak.NEW_LINENEW_LINEUzak Winterspring'de baykuş canavarlarından oluşan bir ırk yaşar. Bir zamanlar saf yaratıklarken, Darkwhisper Geçidi'nin şeytani yayılımları tarafından delirtildiler ve şimdi çılgınca karlarda dolaşıyorlar.NEW_LINENEW_LINEParşömenini mürekkeplemek için onların kanına ihtiyacım var. Getir onu bana.",
    ["Objectives"]="Yanan Bozkırlardaki Mor'zul Kan Getiren'e 30 şişe Öfkeli Canavar Kanı getir.",
    ["Progress"]="Öfkeli baykuş canavarlarını gördün mü, YOUR_NAME ? Bu yaratıkların büyüsü çok güçlüdür ve işkence edilmiş formlarından akan kanda yoğunlaşır.",
    ["Completion"]="Ah, çok iyi. Bu kanı damıtarak mürekkep haline getireceğim ve sana söz verdiğim parşömen için kullanacağım. Ve belki biraz da kendime ayırırım, çünkü tadının oldukça coşkulu olduğunu duydum...",
    ["minlevel"]="0",
    ["questlevel"]="0",
    }, -- end Kanın Öfkesi

    -- Wildeyes
    ["7564"] = {
    ["Title"]="Wildeyes",
    ["Description"]="Hizmetkarım Gorzeeki, yetenekli bir simyacıdır. Parşömeniniz için ihtiyacım olan mürekkebi hazırlayabilir. Aldığın kanı bir araya getirdim; Gorzeeki'ye götür ki işine başlayabilsin.",
