    -- Ruh Totemi
    ["8412"] = {
    ["Title"]="Ruh Totemi",
    ["Description"]="Bu yerin elemental ruhları artık benden hoşlanmıyor.NEW_LINENEW_LINETotemleri herkesten daha iyi biliyorsun ve beni koruyacak bir ruh totemine ihtiyacım var. Zaten elementlerimiz var, şimdi daha doğal bir şeye ihtiyacımız var. Daha ilkel.NEW_LINENEW_LINEBatı Plagueland'da ayıları pençeleri için, örümcekleri de gözleri için öldürebilirsiniz. Leş kuşları her şeyi yer, bu yüzden ikisinden birine sahip olabilirler.",
